import type * as Square from "../index";
/**
 * Result `data` payload. Either an array of objects keyed by member name (default); a compact `{ members, dataset }` object when `responseFormat=compact`; or a columnar `{ members, columns }` object when `responseFormat=columnar`.
 */
export type LoadResultData = Square.LoadResultDataRow | Square.LoadResultDataCompact | Square.LoadResultDataColumnar;
